<span class="line"><span style="color:#D4D4D4;">			*</span><span style="color:#9CDCFE;">criteria</span><span style="color:#D4D4D4;"> = criteria.</span><span style="color:#DCDCAA;">Col</span><span style="color:#D4D4D4;">(</span><span style="color:#CE9178;">&quot;delete_at&quot;</span><span style="color:#D4D4D4;">).</span><span style="color:#DCDCAA;">IsNull</span><span style="color:#D4D4D4;">()</span></span>
